import { parseSync } from "oxc-parser";

import {
  parseCanvasFile,
  type CanvasSourceSpan,
  type ParsedCanvasFile,
  type ParsedCanvasImport,
  type ParsedCanvasStoryboard,
} from "./parser";

export type CanvasSourceEdit = {
  start: number;
  end: number;
  value: string;
};

export type CanvasEditResult = {
  source: string;
  edits: CanvasSourceEdit[];
  parsed: ParsedCanvasFile;
};

export type CanvasEditorLayout = {
  x: number;
  y: number;
  width: number;
  height: number;
  zIndex?: number;
  intrinsicSizing?: "root-element";
};

export type AddCanvasStoryboardInput =
  | {
      kind: "component";
      id: string;
      layout: CanvasEditorLayout;
      name?: string;
      componentExpression?: string;
      // Pre-formatted object-literal expression (e.g. `{ a: "s", b: expr }`)
      // emitted as `props={<value>}` after `component=`. Used by migration to
      // render `render: () => <C a={b} />` as `component={C} props={{ a: b }}`.
      props?: string;
      componentImport?: {
        localName: string;
        source: string;
        importedName?: string;
      };
    }
  | {
      // Per-storyboard fallback for legacy object shapes migration cannot
      // convert natively: emits `<LegacyStoryboardV1 id storyboard={Expr} />`.
      // The wrapper reads name/layout off the referenced object, so no
      // name/layout attributes are emitted here.
      kind: "legacy-v1";
      id: string;
      storyboardExpression: string;
    }
  | {
      kind: "route";
      id: string;
      route: string;
      layout: CanvasEditorLayout;
      name?: string;
    }
  | {
      kind: "html";
      id: string;
      layout: CanvasEditorLayout;
      name?: string;
      filepath?: string;
      src?: string;
    };

type SdkComponent =
  | "Storyboard"
  | "LegacyStoryboardV1"
  | "RouteStoryboard"
  | "HtmlStoryboard";

export function applyCanvasSourceEdits(
  source: string,
  edits: readonly CanvasSourceEdit[],
): string {
  const sorted = [...edits].sort((left, right) => right.start - left.start);
  let previousStart = source.length + 1;
  let nextSource = source;

  for (const edit of sorted) {
    if (
      edit.start < 0 ||
      edit.end < edit.start ||
      edit.end > source.length ||
      edit.end > previousStart
    ) {
      throw new Error(
        `Invalid overlapping canvas source edit ${edit.start}:${edit.end}`,
      );
    }
    nextSource =
      nextSource.slice(0, edit.start) + edit.value + nextSource.slice(edit.end);
    previousStart = edit.start;
  }

  return nextSource;
}

export function updateCanvasName(options: {
  filePath: string;
  source: string;
  name: string;
}): CanvasEditResult {
  return editCanvasStringAttribute(
    options,
    "name",
    requireNonEmpty(options.name, "Canvas name"),
    (parsed) => ({
      valueSpan: parsed.nameSpan,
      attributeSpan: parsed.nameAttributeSpan,
    }),
  );
}

export function updateCanvasPath(options: {
  filePath: string;
  source: string;
  path: string;
}): CanvasEditResult {
  return editCanvasStringAttribute(
    options,
    "path",
    requireNonEmpty(options.path, "Canvas path"),
    (parsed) => ({
      valueSpan: parsed.pathSpan,
      attributeSpan: parsed.pathAttributeSpan,
    }),
  );
}

export function updateCanvasBackgroundColor(options: {
  filePath: string;
  source: string;
  backgroundColor?: string;
}): CanvasEditResult {
  return editCanvasStringAttribute(
    options,
    "backgroundColor",
    options.backgroundColor && options.backgroundColor.trim() !== ""
      ? options.backgroundColor
      : undefined,
    (parsed) => ({
      valueSpan: parsed.backgroundColorSpan,
      attributeSpan: parsed.backgroundColorAttributeSpan,
    }),
  );
}

function editCanvasStringAttribute(
  options: { filePath: string; source: string },
  attributeName: string,
  value: string | undefined,
  selectSpans: (parsed: ParsedCanvasFile) => {
    valueSpan?: CanvasSourceSpan;
    attributeSpan?: CanvasSourceSpan;
  },
): CanvasEditResult {
  const parsed = parseCanvasFile(options.filePath, options.source);
  const spans = selectSpans(parsed);
  const edit = upsertJsxStringAttribute({
    source: options.source,
    openingElementSpan: requiredSpan(
      parsed.canvasOpeningElementSpan,
      "Canvas opening element not found",
    ),
    valueSpan: spans.valueSpan,
    attributeSpan: spans.attributeSpan,
    name: attributeName,
    value,
  });
  return applyResult(options.source, parsed, edit ? [edit] : []);
}

export function updateStoryboardName(options: {
  filePath: string;
  source: string;
  storyboardId: string;
  name?: string;
}): CanvasEditResult {
  const parsed = parseCanvasFile(options.filePath, options.source);
  const storyboard = findStoryboard(parsed, options.storyboardId);
  if (storyboard.legacyV1) {
    const edit = upsertObjectStringProperty({
      source: options.source,
      objectClose: storyboard.legacyV1.objectClose,
      valueSpan: storyboard.nameSpan,
      propertySpan: storyboard.legacyV1.namePropertySpan,
      name: "name",
      value:
        options.name && options.name.trim() !== "" ? options.name : undefined,
    });
    return applyResult(options.source, parsed, edit ? [edit] : []);
  }

  const edit = upsertJsxStringAttribute({
    source: options.source,
    openingElementSpan: requireStoryboardOpeningSpan(
      storyboard,
      options.storyboardId,
    ),
    valueSpan: storyboard.nameSpan,
    attributeSpan: storyboard.nameAttributeSpan,
    name: "name",
    value:
      options.name && options.name.trim() !== "" ? options.name : undefined,
  });
  return applyResult(options.source, parsed, edit ? [edit] : []);
}

export function updateStoryboardId(options: {
  filePath: string;
  source: string;
  storyboardId: string;
  nextId: string;
}): CanvasEditResult {
  const nextId = requireNonEmpty(options.nextId, "Storyboard id");
  const parsed = parseCanvasFile(options.filePath, options.source);
  const storyboard = findStoryboard(parsed, options.storyboardId);
  const duplicate = parsed.storyboards.find(
    (item) =>
      item.storyboardKey === nextId &&
      item.storyboardKey !== storyboard.storyboardKey,
  );
  if (duplicate) {
    throw new Error(`Storyboard id "${nextId}" already exists`);
  }
  const edit = upsertJsxStringAttribute({
    source: options.source,
    openingElementSpan: requireStoryboardOpeningSpan(
      storyboard,
      options.storyboardId,
    ),
    valueSpan: storyboard.idSpan,
    attributeSpan: storyboard.idAttributeSpan,
    name: "id",
    value: nextId,
  });
  return applyResult(options.source, parsed, [edit]);
}

export function updateStoryboardLayout(options: {
  filePath: string;
  source: string;
  storyboardId: string;
  layout: Partial<CanvasEditorLayout>;
}): CanvasEditResult {
  const parsed = parseCanvasFile(options.filePath, options.source);
  const storyboard = findStoryboard(parsed, options.storyboardId);
  const spans = storyboard.layoutSpans;
  if (!spans) {
    throw new Error(
      `Storyboard "${options.storyboardId}" has no editable layout`,
    );
  }

  const edits: CanvasSourceEdit[] = [];
  for (const key of ["x", "y", "width", "height"] as const) {
    if (options.layout[key] === undefined) continue;
    const span = spans[key];
    if (!span) {
      throw new Error(
        `Storyboard "${options.storyboardId}" layout.${key} is not editable`,
      );
    }
    edits.push({
      start: span.start,
      end: span.end,
      value: String(roundLayoutNumber(options.layout[key])),
    });
  }

  if (options.layout.zIndex !== undefined) {
    const value = String(roundLayoutNumber(options.layout.zIndex));
    edits.push(
      spans.zIndex
        ? { start: spans.zIndex.start, end: spans.zIndex.end, value }
        : insertLayoutProperty(options.source, spans, `zIndex: ${value}`),
    );
  }

  if (options.layout.intrinsicSizing !== undefined) {
    const value = JSON.stringify(options.layout.intrinsicSizing);
    edits.push(
      spans.intrinsicSizing
        ? {
            start: spans.intrinsicSizing.start,
            end: spans.intrinsicSizing.end,
            value,
          }
        : insertLayoutProperty(
            options.source,
            spans,
            `intrinsicSizing: ${value}`,
          ),
    );
  }

  return applyResult(options.source, parsed, edits);
}

export function updateStoryboardComponent(options: {
  filePath: string;
  source: string;
  storyboardId: string;
  componentExpression: string;
  componentImport?: {
    localName: string;
    source: string;
    importedName?: string;
  };
}): CanvasEditResult {
  const parsed = parseCanvasFile(options.filePath, options.source);
  const storyboard = findStoryboard(parsed, options.storyboardId);
  if (storyboard.kind !== "component") {
    throw new Error(
      `Storyboard "${options.storyboardId}" is not a component storyboard`,
    );
  }

  const imports: string[] = [];
  if (options.componentImport) {
    const importLine = buildMissingComponentImportLine(
      parsed,
      options.source,
      options.componentImport,
    );
    if (importLine) imports.push(importLine);
  }

  const importEdit = buildImportInsertionEdit(options.source, parsed, imports);
  const componentEdit = upsertJsxExpressionAttribute({
    source: options.source,
    openingElementSpan: requireStoryboardOpeningSpan(
      storyboard,
      options.storyboardId,
    ),
    expressionSpan: storyboard.component?.span,
    attributeSpan: storyboard.component?.attributeSpan,
    name: "component",
    value: requireNonEmpty(
      options.componentExpression,
      "Storyboard component expression",
    ),
  });

  return applyResult(options.source, parsed, [
    ...(importEdit ? [importEdit] : []),
    componentEdit,
  ]);
}

