export function updateHtmlStoryboardSource(options: {
  filePath: string;
  source: string;
  storyboardId: string;
  filepath?: string;
  src?: string;
}): CanvasEditResult {
  const parsed = parseCanvasFile(options.filePath, options.source);
  const storyboard = findStoryboard(parsed, options.storyboardId);
  if (storyboard.kind !== "html") {
    throw new Error(
      `Storyboard "${options.storyboardId}" is not an html storyboard`,
    );
  }
  const filepath =
    options.filepath && options.filepath.trim() !== ""
      ? options.filepath.trim()
      : undefined;
  const src =
    options.src && options.src.trim() !== "" ? options.src : undefined;
  if (!filepath && !src) {
    throw new Error("HTML storyboard source requires filepath or src");
  }

  const openingElementSpan = requireStoryboardOpeningSpan(
    storyboard,
    options.storyboardId,
  );
  const filepathEdit = upsertJsxStringAttribute({
    source: options.source,
    openingElementSpan,
    valueSpan: storyboard.filepathSpan,
    attributeSpan: storyboard.filepathAttributeSpan,
    name: "filepath",
    value: filepath,
  });
  const srcEdit = upsertJsxStringAttribute({
    source: options.source,
    openingElementSpan,
    valueSpan: storyboard.srcSpan,
    attributeSpan: storyboard.srcAttributeSpan,
    name: "src",
    value: src,
  });

  return applyResult(options.source, parsed, [filepathEdit, srcEdit]);
}

export function addCanvasStoryboard(options: {
  filePath: string;
  source: string;
  storyboard: AddCanvasStoryboardInput;
}): CanvasEditResult {
  const parsed = parseCanvasFile(options.filePath, options.source);
  if (
    parsed.storyboards.some(
      (item) => item.storyboardKey === options.storyboard.id,
    )
  ) {
    throw new Error(`Storyboard id "${options.storyboard.id}" already exists`);
  }

  const imports: string[] = [];
  const sdkComponent = sdkComponentForStoryboard(options.storyboard.kind);
  const sdkTag = resolveSdkTag(parsed, sdkComponent);
  let storyboardTag = sdkTag.tag;
  if (sdkTag.importLine) {
    imports.push(sdkTag.importLine);
    storyboardTag = sdkTag.tag;
  }

  let componentExpression: string | undefined;
  if (options.storyboard.kind === "component") {
    componentExpression =
      options.storyboard.componentExpression ??
      options.storyboard.componentImport?.localName;
    if (!componentExpression) {
      throw new Error(
        "Component storyboard requires componentExpression or componentImport",
      );
    }
    if (options.storyboard.componentImport) {
      const importLine = buildMissingComponentImportLine(
        parsed,
        options.source,
        options.storyboard.componentImport,
      );
      if (importLine) imports.push(importLine);
    }
  }

  const importEdit = buildImportInsertionEdit(options.source, parsed, imports);
  const insertionEdit = buildCanvasChildInsertionEdit({
    source: options.source,
    parsed,
    tag: storyboardTag,
    storyboard: options.storyboard,
    componentExpression,
  });

  const edits = [...(importEdit ? [importEdit] : []), insertionEdit];
  return applyResult(options.source, parsed, edits);
}

export function removeCanvasStoryboard(options: {
  filePath: string;
  source: string;
  storyboardId: string;
  removeUnusedComponentImport?: boolean;
}): CanvasEditResult {
  const parsed = parseCanvasFile(options.filePath, options.source);
  const storyboard = findStoryboard(parsed, options.storyboardId);
  const edits: CanvasSourceEdit[] = [
    {
      ...expandToFullLines(options.source, storyboard.jsxElementSpan),
      value: "",
    },
  ];

  if (options.removeUnusedComponentImport ?? true) {
    const importEdit = buildUnusedComponentImportRemoval({
      source: options.source,
      parsed,
      deletedStoryboard: storyboard,
      deletionEdit: edits[0],
    });
    if (importEdit) edits.push(importEdit);
  }

  const result = applyResult(options.source, parsed, edits);
  return {
    ...result,
    source: collapseBlankLines(result.source, detectNewline(options.source)),
  };
}

function applyResult(
  source: string,
  parsed: ParsedCanvasFile,
  edits: readonly (CanvasSourceEdit | null | undefined)[],
): CanvasEditResult {
  const compactEdits = edits.filter((edit): edit is CanvasSourceEdit => {
    if (!edit) return false;
    return source.slice(edit.start, edit.end) !== edit.value;
  });
  return {
    source: applyCanvasSourceEdits(source, compactEdits),
    edits: compactEdits,
    parsed,
  };
}

function findStoryboard(
  parsed: ParsedCanvasFile,
  storyboardId: string,
): ParsedCanvasStoryboard {
  const storyboard = parsed.storyboards.find(
    (item) => item.storyboardKey === storyboardId,
  );
  if (!storyboard) {
    throw new Error(`Storyboard "${storyboardId}" not found`);
  }
  return storyboard;
}

function requireStoryboardOpeningSpan(
  storyboard: ParsedCanvasStoryboard,
  storyboardId: string,
): CanvasSourceSpan {
  return requiredSpan(
    storyboard.openingElementSpan,
    `Storyboard "${storyboardId}" opening element not found`,
  );
}

function upsertJsxStringAttribute(options: {
  source: string;
  openingElementSpan: CanvasSourceSpan;
  valueSpan?: CanvasSourceSpan;
  attributeSpan?: CanvasSourceSpan;
  name: string;
  value?: string;
}): CanvasSourceEdit | null {
  if (options.value === undefined) {
    if (!options.attributeSpan) return null;
    return {
      ...expandJsxAttributeRemoval(options.source, options.attributeSpan),
      value: "",
    };
  }

  const value = JSON.stringify(options.value);
  if (options.valueSpan) {
    return {
      start: options.valueSpan.start,
      end: options.valueSpan.end,
      value,
    };
  }

  const offset = findOpeningElementAttributeInsertionOffset(
    options.source,
    options.openingElementSpan,
  );
  return {
    start: offset,
    end: offset,
    value: ` ${options.name}={${value}}`,
  };
}

function upsertObjectStringProperty(options: {
  source: string;
  objectClose?: number;
  valueSpan?: CanvasSourceSpan;
  propertySpan?: CanvasSourceSpan;
  name: string;
  value?: string;
}): CanvasSourceEdit | null {
  if (options.value === undefined) {
    if (!options.propertySpan) return null;
    return {
      ...expandObjectPropertyRemoval(options.source, options.propertySpan),
      value: "",
    };
  }

  const value = JSON.stringify(options.value);
  if (options.valueSpan) {
    return {
      start: options.valueSpan.start,
      end: options.valueSpan.end,
      value,
    };
  }

  if (typeof options.objectClose !== "number") {
    throw new Error(`Object close not found for "${options.name}" property`);
  }

  return insertObjectProperty(
    options.source,
    options.objectClose,
    `${options.name}: ${value}`,
  );
}

function upsertJsxExpressionAttribute(options: {
  source: string;
  openingElementSpan: CanvasSourceSpan;
  expressionSpan?: CanvasSourceSpan;
  attributeSpan?: CanvasSourceSpan;
  name: string;
  value?: string;
}): CanvasSourceEdit | null {
  if (options.value === undefined) {
    if (!options.attributeSpan) return null;
    return {
      ...expandJsxAttributeRemoval(options.source, options.attributeSpan),
      value: "",
    };
  }

  if (options.expressionSpan) {
    return {
      start: options.expressionSpan.start,
      end: options.expressionSpan.end,
      value: options.value,
    };
  }

  const offset = findOpeningElementAttributeInsertionOffset(
    options.source,
    options.openingElementSpan,
  );
  return {
    start: offset,
    end: offset,
    value: ` ${options.name}={${options.value}}`,
  };
}

function insertLayoutProperty(
  source: string,
  spans: NonNullable<ParsedCanvasStoryboard["layoutSpans"]>,
  propertySource: string,
): CanvasSourceEdit {
  if (typeof spans.layoutClose !== "number") {
    throw new Error("Layout object close span not found");
  }
  return insertObjectProperty(source, spans.layoutClose, propertySource);
}

function insertObjectProperty(
  source: string,
  objectClose: number,
  propertySource: string,
): CanvasSourceEdit {
  const offset = trimWhitespaceBeforeOffset(source, objectClose);
  const previous = previousMeaningfulCharacter(source, offset);
  return {
    start: offset,
    end: offset,
    value: `${previous === "{" || previous === "," ? " " : ", "}${propertySource}`,
  };
}

function formatStoryboardElement(options: {
  source: string;
  insertionOffset: number;
  tag: string;
  storyboard: AddCanvasStoryboardInput;
  componentExpression?: string;
}): string {
  const newline = detectNewline(options.source);
  const closingIndent = lineIndentAt(options.source, options.insertionOffset);
  const indent = `${closingIndent}  `;
  const firstLineIndent = "  ";
  const propIndent = `${indent}  `;
  const props = storyboardElementProps(
    options.storyboard,
    options.componentExpression,
  );

  return `${firstLineIndent}<${options.tag}${newline}${props
    .map((prop) => `${propIndent}${prop}`)
    .join(newline)}${newline}${indent}/>${newline}${closingIndent}`;
}

function buildCanvasChildInsertionEdit(options: {
  source: string;
  parsed: ParsedCanvasFile;
  tag: string;
  storyboard: AddCanvasStoryboardInput;
  componentExpression?: string;
}): CanvasSourceEdit {
  const insertionOffset = options.parsed.canvasChildrenInsertionOffset;
  if (typeof insertionOffset === "number") {
    return {
      start: insertionOffset,
      end: insertionOffset,
      value: formatStoryboardElement({
        source: options.source,
        insertionOffset,
        tag: options.tag,
        storyboard: options.storyboard,
        componentExpression: options.componentExpression,
      }),
    };
  }

  const openingSpan = options.parsed.canvasOpeningElementSpan;
  if (!openingSpan) {
    throw new Error("Canvas closing element not found");
  }

  const openingSource = options.source.slice(
    openingSpan.start,
    openingSpan.end,
  );
  const selfClosingMatch = openingSource.match(/\s*\/\s*>$/);
  const canvasName = openingSource.match(
    /^<\s*([A-Za-z_$][\w$]*(?:\.[A-Za-z_$][\w$]*)*)/,
  )?.[1];
  if (!selfClosingMatch || !canvasName) {
    throw new Error("Canvas closing element not found");
  }

  const newline = detectNewline(options.source);
  const replacementStart = openingSpan.end - selfClosingMatch[0].length;
  const closingIndent = lineIndentAt(options.source, openingSpan.start);
  const childIndent = `${closingIndent}  `;
  const propIndent = `${childIndent}  `;
  const props = storyboardElementProps(
    options.storyboard,
    options.componentExpression,
  );

  return {
    start: replacementStart,
    end: openingSpan.end,
    value: `>${newline}${childIndent}<${options.tag}${newline}${props
      .map((prop) => `${propIndent}${prop}`)
      .join(
        newline,
      )}${newline}${childIndent}/>${newline}${closingIndent}</${canvasName}>`,
  };
}

function storyboardElementProps(
  storyboard: AddCanvasStoryboardInput,
  componentExpression?: string,
): string[] {
  const idProp = formatJsxStringAttribute(
    "id",
    requireNonEmpty(storyboard.id, "Storyboard id"),
  );

  // LegacyStoryboardV1 carries only `id` + `storyboard={Expr}`; name and
  // layout live on the referenced object, so they are never emitted here.
  if (storyboard.kind === "legacy-v1") {
    return [idProp, `storyboard={${storyboard.storyboardExpression}}`];
  }

  return [
    idProp,
    ...(storyboard.name && storyboard.name.trim() !== ""
      ? [formatJsxStringAttribute("name", storyboard.name)]
      : []),
    ...storyboardKindProps(storyboard, componentExpression),
    `layout={{ ${formatLayout(storyboard.layout)} }}`,
  ];
}

/**
 * Format a JSX string attribute. Prefers the idiomatic plain form
 * (`name="value"`) and falls back to the expression form (`name={"value"}`)
 * when the plain form can't represent the value faithfully: JSX string
 * attributes don't process backslash escapes but DO decode HTML entities, so
 * any value that JSON-escapes (quotes, backslashes, control characters) or
 * contains `&` must go through a braced string literal.
 */
export function formatJsxStringAttribute(name: string, value: string): string {
  const encoded = JSON.stringify(value);
  const plainSafe = encoded === `"${value}"` && !value.includes("&");
  return plainSafe ? `${name}=${encoded}` : `${name}={${encoded}}`;
}

function storyboardKindProps(
  // legacy-v1 never reaches here: `storyboardElementProps` emits its
  // `storyboard={…}` prop directly (it has no name/layout attributes).
  storyboard: Exclude<AddCanvasStoryboardInput, { kind: "legacy-v1" }>,
  componentExpression?: string,
): string[] {
  if (storyboard.kind === "component") {
    return [
      `component={${componentExpression}}`,
      ...(storyboard.props && storyboard.props.trim() !== ""
        ? [`props={${storyboard.props.trim()}}`]
        : []),
    ];
  }
  if (storyboard.kind === "route") {
    return [formatJsxStringAttribute("route", storyboard.route)];
  }
  return [
    ...(storyboard.filepath
      ? [formatJsxStringAttribute("filepath", storyboard.filepath)]
      : []),
    ...(storyboard.src
      ? [formatJsxStringAttribute("src", storyboard.src)]
      : []),
  ];
}

function formatLayout(layout: CanvasEditorLayout): string {
  return [
    `x: ${roundLayoutNumber(layout.x)}`,
    `y: ${roundLayoutNumber(layout.y)}`,
    `width: ${roundLayoutNumber(layout.width)}`,
    `height: ${roundLayoutNumber(layout.height)}`,
    ...(layout.zIndex === undefined
      ? []
      : [`zIndex: ${roundLayoutNumber(layout.zIndex)}`]),
    ...(layout.intrinsicSizing
      ? [`intrinsicSizing: ${JSON.stringify(layout.intrinsicSizing)}`]
      : []),
  ].join(", ");
}

function sdkComponentForStoryboard(
  kind: AddCanvasStoryboardInput["kind"],
): SdkComponent {
  if (kind === "route") return "RouteStoryboard";
  if (kind === "html") return "HtmlStoryboard";
  if (kind === "legacy-v1") return "LegacyStoryboardV1";
  return "Storyboard";
}

function resolveSdkTag(
  parsed: ParsedCanvasFile,
  component: SdkComponent,
): { tag: string; importLine?: string } {
  for (const item of parsed.imports) {
    if (item.source !== "tempo-sdk/canvas") continue;
    if (item.kind === "namespace")
      return { tag: `${item.localName}.${component}` };
    if (item.importedName === component) return { tag: item.localName };
  }

  const localName = pickAvailableIdentifier(parsed, `TempoCanvas${component}`);
  return {
    tag: localName,
    importLine: `import { ${component} as ${localName} } from "tempo-sdk/canvas";`,
  };
}

function buildMissingComponentImportLine(
  parsed: ParsedCanvasFile,
  source: string,
  componentImport: {
    localName: string;
    source: string;
    importedName?: string;
  },
): string | null {
  const existing = parsed.imports.find(
    (item) => item.localName === componentImport.localName,
  );
  if (existing) {
    if (existing.source !== componentImport.source) {
      throw new Error(
        `Import binding "${componentImport.localName}" already exists`,
      );
    }
    return null;
  }
  // Collision check that THROWS — must not fire on the name merely appearing
  // inside a string literal (e.g. `<Canvas name="Card Demo">` blocking a `Card`
  // import), so use the AST-based node scan, never the textual `hasIdentifier`.
  if (
    sourceContainsIdentifierNode(
      parsed.filePath,
      source,
      componentImport.localName,
    )
  ) {
    throw new Error(`Identifier "${componentImport.localName}" already exists`);
  }

  if (
    !componentImport.importedName ||
    componentImport.importedName === "default"
  ) {
    return `import ${componentImport.localName} from ${JSON.stringify(
      componentImport.source,
    )};`;
  }

  const specifier =
    componentImport.importedName === componentImport.localName
      ? componentImport.localName
      : `${componentImport.importedName} as ${componentImport.localName}`;
  return `import { ${specifier} } from ${JSON.stringify(componentImport.source)};`;
}

function buildImportInsertionEdit(
  source: string,
  parsed: ParsedCanvasFile,
  importLines: readonly string[],
): CanvasSourceEdit | null {
  if (importLines.length === 0) return null;
  const newline = detectNewline(source);
  const uniqueLines = Array.from(new Set(importLines));
  const lastImport = parsed.imports.reduce<ParsedCanvasImport | null>(
    (latest, item) =>
      !latest || item.declarationSpan.end > latest.declarationSpan.end
        ? item
        : latest,
    null,
  );

  if (lastImport) {
    return {
      start: lastImport.declarationSpan.end,
      end: lastImport.declarationSpan.end,
      value: `${newline}${uniqueLines.join(newline)}`,
    };
  }

  const offset = topLevelInsertionOffset(source);
  return {
    start: offset,
    end: offset,
    value: `${uniqueLines.join(newline)}${newline}`,
  };
}

function buildUnusedComponentImportRemoval(options: {
  source: string;
  parsed: ParsedCanvasFile;
  deletedStoryboard: ParsedCanvasStoryboard;
  deletionEdit: CanvasSourceEdit;
}): CanvasSourceEdit | null {
  const componentImport = options.deletedStoryboard.component?.import;
  if (!componentImport || componentImport.importKind === "type") return null;

  const usedByRemainingStoryboard = options.parsed.storyboards.some(
    (storyboard) =>
      storyboard.storyboardKey !== options.deletedStoryboard.storyboardKey &&
      storyboard.component?.import?.localName === componentImport.localName,
  );
  if (usedByRemainingStoryboard) return null;

  const sourceAfterStoryboardDelete = applyCanvasSourceEdits(options.source, [
    options.deletionEdit,
  ]);

  if (componentImport.specifierCount === 1) {
    const sourceWithoutImport = removeSpanText(
      sourceAfterStoryboardDelete,
      componentImport.declarationSpan,
    );
    if (hasIdentifier(sourceWithoutImport, componentImport.localName))
      return null;

    return {
      ...expandToFullLines(options.source, componentImport.declarationSpan),
      value: "",
    };
  }

  if (
    componentImport.kind !== "named" ||
    componentImport.hasDefaultSpecifier ||
    componentImport.hasNamespaceSpecifier ||
    componentImport.namedSpecifierCount <= 1
  ) {
    return null;
  }

  const specifierRange = expandImportSpecifierRemovalRange(
    options.source,
    componentImport.span,
  );
  const sourceWithoutImport = removeSpanText(
    sourceAfterStoryboardDelete,
    specifierRange,
  );
  if (hasIdentifier(sourceWithoutImport, componentImport.localName))
    return null;

  return {
    ...specifierRange,
    value: "",
  };
}

function expandImportSpecifierRemovalRange(
  source: string,
  span: CanvasSourceSpan,
): CanvasSourceSpan {
  const lineStart = Math.max(source.lastIndexOf("\n", span.start - 1) + 1, 0);
  const nextNewline = source.indexOf("\n", span.end);
  const lineEnd = nextNewline >= 0 ? nextNewline + 1 : source.length;
  const before = source.slice(lineStart, span.start);
  const after = source.slice(span.end, lineEnd);
  if (/^[ \t]*$/.test(before) && /^[ \t]*(,)?[ \t]*(\r?\n)?$/.test(after)) {
    return { start: lineStart, end: lineEnd };
  }

  let start = span.start;
  let end = span.end;
  while (end < source.length && /\s/.test(source[end] ?? "")) end++;
  if (source[end] === ",") {
    end++;
    while (
      end < source.length &&
      (source[end] === " " || source[end] === "\t")
    ) {
      end++;
    }
    return { start, end };
  }

  while (
    start > 0 &&
    (source[start - 1] === " " || source[start - 1] === "\t")
  ) {
    start--;
  }
  if (source[start - 1] === ",") {
    start--;
    while (
      start > 0 &&
      (source[start - 1] === " " || source[start - 1] === "\t")
    ) {
      start--;
    }
  }
  return { start, end };
}

function removeSpanText(source: string, span: CanvasSourceSpan): string {
  return source.slice(0, span.start) + source.slice(span.end);
}

function findOpeningElementAttributeInsertionOffset(
  source: string,
  span: CanvasSourceSpan,
): number {
  const close = source.lastIndexOf(">", span.end - 1);
  if (close < span.start) {
    throw new Error("JSX opening element close not found");
  }
  return source[close - 1] === "/" ? close - 1 : close;
}

function expandJsxAttributeRemoval(
  source: string,
  span: CanvasSourceSpan,
): CanvasSourceSpan {
  let start = span.start;
  let end = span.end;

  while (
    start > 0 &&
    (source[start - 1] === " " || source[start - 1] === "\t")
  ) {
    start--;
  }
  while (end < source.length && (source[end] === " " || source[end] === "\t")) {
    end++;
  }
  return { start, end };
}

function expandObjectPropertyRemoval(
  source: string,
  span: CanvasSourceSpan,
): CanvasSourceSpan {
  let start = span.start;
  let end = span.end;

  while (start > 0 && /\s/.test(source[start - 1] ?? "")) start--;
  while (end < source.length && /\s/.test(source[end] ?? "")) end++;

  if (source[end] === ",") {
    end++;
    while (
      end < source.length &&
      (source[end] === " " || source[end] === "\t")
    ) {
      end++;
    }
    return { start, end };
  }

  let comma = start - 1;
  while (comma >= 0 && /\s/.test(source[comma] ?? "")) comma--;
  if (source[comma] === ",") {
    start = comma;
  }
  return { start, end };
}

export function expandToFullLines(
  source: string,
  span: CanvasSourceSpan,
): CanvasSourceSpan {
  let start = span.start;
  let end = span.end;
  while (
    start > 0 &&
    source[start - 1] !== "\n" &&
    source[start - 1] !== "\r"
  ) {
    start--;
  }
  if (start > 0) {
    if (source[start - 1] === "\n") start--;
    if (start > 0 && source[start - 1] === "\r") start--;
  }
  while (end < source.length && (source[end] === " " || source[end] === "\t")) {
    end++;
  }
  if (source.slice(end, end + 2) === "\r\n") {
    end += 2;
  } else if (source[end] === "\n" || source[end] === "\r") {
    end++;
  }
  return { start, end };
}

export function expandStatementForward(
  source: string,
  span: CanvasSourceSpan,
): CanvasSourceSpan {
  let end = span.end;
  while (end < source.length && (source[end] === " " || source[end] === "\t")) {
    end++;
  }
  if (source.slice(end, end + 2) === "\r\n") {
    end += 2;
  } else if (source[end] === "\n" || source[end] === "\r") {
    end++;
  }
  return { start: span.start, end };
}

function lineIndentAt(source: string, offset: number): string {
  const lineStart = Math.max(source.lastIndexOf("\n", offset - 1) + 1, 0);
  const linePrefix = source.slice(lineStart, offset);
  const match = linePrefix.match(/^[ \t]*/);
  return match?.[0] ?? "";
}

function previousMeaningfulCharacter(source: string, offset: number): string {
  for (let index = offset - 1; index >= 0; index -= 1) {
    const character = source[index] ?? "";
    if (!/\s/.test(character)) return character;
  }
  return "";
}

function trimWhitespaceBeforeOffset(source: string, offset: number): number {
  let nextOffset = offset;
  while (nextOffset > 0 && /\s/.test(source[nextOffset - 1] ?? "")) {
    nextOffset--;
  }
  return nextOffset;
}

export function collapseBlankLines(source: string, newline: string): string {
  return newline === "\r\n"
    ? source.replace(/(\r\n){3,}/g, "\r\n\r\n")
    : source.replace(/\n{3,}/g, "\n\n");
}

export function detectNewline(source: string): "\n" | "\r\n" {
  return source.includes("\r\n") ? "\r\n" : "\n";
}

export function topLevelInsertionOffset(source: string): number {
  let offset = 0;
  if (source.startsWith("#!")) {
    const newline = source.indexOf("\n");
    offset = newline >= 0 ? newline + 1 : source.length;
  }

  while (true) {
    const nextLineEnd = source.indexOf("\n", offset);
    const end = nextLineEnd >= 0 ? nextLineEnd + 1 : source.length;
    const line = source.slice(offset, end).trim();
    if (!/^["']use [^"']+["'];?$/.test(line)) break;
    offset = end;
  }

  return offset;
}

function pickAvailableIdentifier(
  parsed: ParsedCanvasFile,
  base: string,
): string {
  const usedImports = new Set(parsed.imports.map((item) => item.localName));
  if (!usedImports.has(base)) return base;
  for (let index = 2; index < 10_000; index += 1) {
    const candidate = `${base}${index}`;
    if (!usedImports.has(candidate)) return candidate;
  }
  throw new Error(`Unable to find available identifier for ${base}`);
}

/**
 * Cheap word-boundary text scan. It matches occurrences inside string literals
 * and comments too, so it is SAFE-DIRECTION ONLY: use it where a false positive
 * is harmless (conservatively keeping an import that might still be used), NEVER
 * for a collision check that throws or blocks an edit — those must use
 * {@link sourceContainsIdentifierNode}, which counts real identifier nodes only.
 */
export function hasIdentifier(source: string, identifier: string): boolean {
  return new RegExp(`\\b${escapeRegExp(identifier)}\\b`).test(source);
}

/**
 * True when `name` appears as a real identifier node (`Identifier` /
 * `JSXIdentifier`) anywhere in `source` — a binding or reference, never a
 * string-literal or comment occurrence. Use this for collision checks that
 * throw or block an edit, so a name appearing only inside a string (e.g.
 * `<Canvas name="Card Demo">` vs a `Card` import) can't masquerade as a
 * declared identifier.
 */
export function sourceContainsIdentifierNode(
  filePath: string,
  source: string,
  name: string,
): boolean {
  const program = (parseSync(filePath, source) as any).program;
  let found = false;
  walkWithParent(program, (node) => {
    if (found) return;
    if (
      (node.type === "Identifier" || node.type === "JSXIdentifier") &&
      node.name === name
    ) {
      found = true;
    }
  });
  return found;
}

/**
 * Depth-first walk that hands each AST node to `visit` along with its parent and
 * the parent field it was reached through — the context callers need to tell a
 * value reference from a property key or member access.
 */
export function walkWithParent(
  node: any,
  visit: (node: any, parent: any, key: string | null) => void,
  parent: any = null,
  key: string | null = null,
  seen = new Set<any>(),
): void {
  if (!node || typeof node !== "object" || seen.has(node)) return;
  seen.add(node);
  if (typeof node.type === "string") visit(node, parent, key);
  for (const [childKey, value] of Object.entries(node)) {
    if (!value || typeof value !== "object") continue;
    if (Array.isArray(value)) {
      for (const item of value)
        walkWithParent(item, visit, node, childKey, seen);
    } else {
      walkWithParent(value, visit, node, childKey, seen);
    }
  }
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function roundLayoutNumber(value: number): number {
  if (typeof value !== "number" || !Number.isFinite(value)) {
    throw new Error("Layout values must be finite numbers");
  }
  return Math.round(value);
}

function requireNonEmpty(value: string, label: string): string {
  const trimmed = value.trim();
  if (!trimmed) {
    throw new Error(`${label} must be non-empty`);
  }
  return trimmed;
}

function requiredSpan<T>(value: T | undefined, message: string): T {
  if (value === undefined) {
    throw new Error(message);
  }
  return value;
}
